def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        c = bins[i]
        if c <= 0:
            priorities[i] = np.inf
            continue
        if item > c:
            priorities[i] = np.inf
            continue
        ratio = item / c
        base_score = 0
        if ratio < 0.1:
            base_score = np.exp(-(ratio * 10)) + np.sin(ratio * 20)
        elif 0.1 <= ratio < 0.4:
            base_score = np.log1p(ratio * 5) * 4 - np.sqrt(ratio) * 2
        elif 0.4 <= ratio < 0.7:
            base_score = (1 / (1 + np.exp(-20 * (ratio - 0.55)))) + np.cos(ratio * 7) * 0.8
        elif 0.7 <= ratio < 0.95:
            base_score = np.tanh(15 * (ratio - 0.7)) + 0.7 + np.sin(ratio * 10)
        else:
            base_score = np.tanh(20 * (ratio - 0.95)) + 1.0
        penalty = 0
        for j in range(1, 8):
            val = (item * j) % c
            frac = val / (c * j)
            if frac < 0.05:
                penalty += frac * 3
            elif 0.05 <= frac < 0.2:
                penalty += frac * 1.5
            else:
                penalty += frac / (j ** 0.7)
        extra_penalty = 0
        for k in range(1, 6):
            if ratio > 0.3 * k:
                exp_val = np.exp(-k * (ratio ** 1.5))
                extra_penalty += exp_val * k * 1.2
            else:
                log_val = np.log1p(k * (ratio ** 0.8) + 2)
                extra_penalty += log_val / (k + 2)
        if c % 3 == 0:
            factor = 1.4
        elif c % 5 == 0:
            factor = 0.9
        else:
            factor = 1.0
        mod_penalty = 0
        for m in range(1, 4):
            test_val = ((item * m) + i) % c
            if test_val / c < 0.15:
                mod_penalty += (test_val / c) * 2 * factor
            else:
                mod_penalty += (test_val / c) * factor / (m + 1)
        total = base_score + penalty * 1.2 + extra_penalty * 0.7 + mod_penalty
        if total < 0:
            total = 0
        priorities[i] = total
    return priorities
